export function HomeEntry() {
  const [loginOpen, setLoginOpen] = useState(false)
  const [visitorName, setVisitorName] = useState("临时游客")
  const [conversationId, setConversationId] = useState("")
  const [interests, setInterests] = useState<string[]>([])
  const [interestOptions, setInterestOptions] = useState(defaultInterests)
  const [messages, setMessages] = useState<Message[]>([
    { role: "assistant", content: "你好，我是你的 AI 数字人导览员。无论你在首页、地图还是景点推荐里，都可以直接问我路线、讲解和服务信息。" },
  ])
  const [input, setInput] = useState("")
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState("")
  const [history, setHistory] = useState<HistoryItem[]>([])
  const [recording, setRecording] = useState(false)
  const abortRef = useRef<AbortController | null>(null)
  const recorderRef = useRef<MediaRecorder | null>(null)
  const audioChunksRef = useRef<Blob[]>([])

  useEffect(() => {
    setApiBase(window.location.origin)
    setVisitorName(localStorage.getItem("dg_visitor_name") || "临时游客")
    try {
      setHistory(JSON.parse(localStorage.getItem("dg_conversation_history") || "[]"))
    } catch {
      setHistory([])
    }

    const params = new URLSearchParams(window.location.search)
    if (params.get("adminLogin") === "1") {
      setLoginOpen(true)
      window.history.replaceState(null, "", "/")
    }
  }, [])

  async function createConversation() {
    setError("")
    const visitorId = localStorage.getItem("dg_visitor_id") || crypto.randomUUID()
    localStorage.setItem("dg_visitor_id", visitorId)
    localStorage.setItem("dg_visitor_name", visitorName || "临时游客")

    const data = await request<any>("/api/conversations", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ visitor_id: `${visitorName || "visitor"}-${visitorId}` }),
    })

    const nextConversationId = data.conversation_id as string
    const nextHistory = [
      { id: nextConversationId, title: `${visitorName || "临时游客"} 的导览会话`, updatedAt: new Date().toLocaleString() },
      ...history,
    ].slice(0, 12)
    setConversationId(nextConversationId)
    setInterests([])
    setInterestOptions(data.interest_options || defaultInterests)
    setMessages([{ role: "assistant", content: data.greeting || "新的导览会话已创建。你可以直接问我景点讲解、游览路线和服务信息。" }])
    setHistory(nextHistory)
    localStorage.setItem("dg_conversation_history", JSON.stringify(nextHistory))
    return nextConversationId
  }

  async function sendMessage(text = input) {
    const content = text.trim()
    if (!content || loading) return

    setError("")
    setLoading(true)
    setInput("")

    try {
      let activeConversationId = conversationId
      if (!activeConversationId) activeConversationId = await createConversation()

      setMessages((current) => [...current, { role: "user", content }, { role: "assistant", content: "" }])
      const controller = new AbortController()
      abortRef.current = controller

      const res = await fetch(`${apiBase()}/api/voice/chat`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ conversation_id: activeConversationId, message: content, language: "zh", explain_mode: "normal" }),
        signal: controller.signal,
      })
      if (!res.ok || !res.body) throw new Error("问答服务暂时不可用")

      const reader = res.body.getReader()
      const decoder = new TextDecoder("utf-8")
      let buffer = ""
      let finalText = ""

      while (true) {
        const { value, done } = await reader.read()
        if (done) break
        buffer += decoder.decode(value, { stream: true })
        const events = buffer.split("\n\n")
        buffer = events.pop() || ""

        for (const event of events) {
          const line = event.split("\n").find((item) => item.startsWith("data:"))
          if (!line) continue
          const payload = JSON.parse(line.slice(5).trim())
          if (payload.type === "delta") finalText += payload.content || ""
          if (payload.type === "done") finalText = payload.content || finalText
          if (payload.type === "error") throw new Error(payload.message || payload.content || "服务暂时不可用")
          setMessages((current) => current.map((item, index) => (index === current.length - 1 ? { ...item, content: finalText } : item)))
        }
      }
    } catch (err: any) {
      if (err?.name !== "AbortError") {
        const message = err?.message || "后端服务暂时无法连接，请确认服务已启动。"
        setError(message)
        setMessages((current) => current.map((item, index) => (index === current.length - 1 ? { ...item, content: message } : item)))
      }
    } finally {
      setLoading(false)
      abortRef.current = null
    }
  }

  async function toggleInterest(tag: string) {
    const next = interests.includes(tag) ? interests.filter((item) => item !== tag) : [...interests, tag]
    setInterests(next)
    if (conversationId) {
      await request(`/api/conversations/${conversationId}/interests`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ interest_tags: next }),
      }).catch(() => {})
    }
  }

  async function recommendRoute() {
    await sendMessage(`请根据我的兴趣偏好规划一条游览路线：${interests.join("，") || "不限"}`)
  }

  async function toggleRecording() {
    if (recording) {
      recorderRef.current?.stop()
      setRecording(false)
      return
    }
    setError("")
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true })
      const recorder = new MediaRecorder(stream)
      audioChunksRef.current = []
      recorder.ondataavailable = (event) => {
        if (event.data.size > 0) audioChunksRef.current.push(event.data)
      }
      recorder.onstop = async () => {
        stream.getTracks().forEach((track) => track.stop())
        const blob = new Blob(audioChunksRef.current, { type: recorder.mimeType || "audio/webm" })
        const form = new FormData()
        form.append("audio", blob, "voice.webm")
        try {
          const data = await request<any>("/api/voice/asr", { method: "POST", body: form })
          if (data.text) await sendMessage(data.text)
        } catch (err: any) {
          setError(err?.message || "语音识别失败")
        }
      }
      recorderRef.current = recorder
      recorder.start()
      setRecording(true)
    } catch {
      setError("无法使用麦克风，请检查浏览器权限")
    }
  }

  async function speakLastReply() {
    const last = [...messages].reverse().find((item) => item.role === "assistant" && item.content)
    if (!last) return
    const res = await fetch(`${apiBase()}/api/voice/tts`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ text: last.content.slice(0, 1000), conversation_id: conversationId || null, language: "zh" }),
    })
    if (!res.ok) return setError("语音合成失败")
    const url = URL.createObjectURL(await res.blob())
    const audio = new Audio(url)
    audio.onended = () => URL.revokeObjectURL(url)
    await audio.play()
  }

  return (
    <main className="min-h-screen bg-[#f5f7f2] text-foreground">
      <nav className="sticky top-0 z-40 border-b border-emerald-950/10 bg-white/82 backdrop-blur-xl">
        <div className="mx-auto flex h-16 max-w-7xl items-center justify-between gap-4 px-4 md:px-6">
          <a href="#home" className="flex items-center gap-2">
            <span className="grid h-9 w-9 place-items-center rounded-full bg-primary text-xs font-black text-primary-foreground">DG</span>
            <span className="text-lg font-semibold">DG AI Guide</span>
          </a>
          <div className="hidden items-center rounded-full bg-emerald-50 p-1 text-sm md:flex">
            <a className="rounded-full px-4 py-2 font-medium text-emerald-950 hover:bg-white" href="#home">首页</a>
            <a className="rounded-full px-4 py-2 font-medium text-emerald-950 hover:bg-white" href="#chat">对话</a>
            <a className="rounded-full px-4 py-2 font-medium text-emerald-950 hover:bg-white" href="#map">地图导览</a>
            <a className="rounded-full px-4 py-2 font-medium text-emerald-950 hover:bg-white" href="#spots">景点推荐</a>
          </div>
          <button type="button" onClick={() => setLoginOpen(true)} className="rounded-full border border-emerald-900/15 px-4 py-2 text-xs font-medium text-emerald-950/60 transition hover:text-emerald-950">
            管理后台
          </button>
        </div>
      </nav>

      <section id="home" className="relative overflow-hidden">
        <div className="absolute inset-0">
          {scenicImages.map((image, index) => (
            <div
              key={image}
              className="scenic-slide absolute inset-0 bg-cover bg-center"
              style={{ backgroundImage: `url(${image})`, animation: "scenicFade 20s infinite", animationDelay: `${index * 5}s`, opacity: index === 0 ? 1 : 0 }}
            />
          ))}
          <div className="absolute inset-0 bg-gradient-to-r from-emerald-950/88 via-emerald-950/58 to-white/10" />
        </div>
        <div className="relative mx-auto grid min-h-[calc(100vh-4rem)] max-w-7xl items-center gap-10 px-4 py-14 md:grid-cols-[1fr_460px] md:px-6">
          <div className="max-w-3xl text-white">
            <div className="mb-6 inline-flex items-center gap-2 rounded-full border border-white/30 bg-white/10 px-4 py-2 text-sm backdrop-blur-md">
              <Sparkles className="h-4 w-4 text-emerald-200" />
              哪里都有数字人带领
            </div>
            <h1 className="text-balance text-5xl font-semibold leading-[1.04] tracking-tight md:text-7xl">
              让每一次游览，都有一位随行数字人
            </h1>
            <p className="mt-6 max-w-2xl text-lg leading-8 text-white/88">
              打开首页就是导览体验。你可以直接问景点、路线、服务设施和拍照建议，数字人会陪你从出发一路走到目的地。
            </p>
            <div className="mt-8 flex flex-wrap gap-3">
              <a href="#chat" className="inline-flex h-12 items-center gap-2 rounded-full bg-primary px-6 text-sm font-semibold text-primary-foreground shadow-lg shadow-emerald-950/20">
                <MessageCircle className="h-4 w-4" />
                开始对话
              </a>
              <a href="#map" className="inline-flex h-12 items-center gap-2 rounded-full border border-white/40 bg-white/10 px-6 text-sm font-semibold text-white backdrop-blur-md">
                <MapPinned className="h-4 w-4" />
                查看地图导览
              </a>
            </div>
          </div>
          <DigitalHuman large />
        </div>
      </section>

      <section id="chat" className="mx-auto grid max-w-7xl gap-5 px-4 py-10 md:px-6 xl:grid-cols-[280px_minmax(0,1fr)_300px]">
        <Card className="p-5 shadow-lg">
          <h2 className="mb-4 flex items-center gap-2 text-lg font-semibold"><Bot className="h-5 w-5 text-primary" />数字人展示</h2>
          <DigitalHuman />
          <Input className="mt-4" value={visitorName} onChange={(event) => setVisitorName(event.target.value)} placeholder="游客昵称" />
          <div className="mt-3 flex flex-wrap gap-2">
            {interestOptions.map((tag) => (
              <button key={tag} type="button" onClick={() => toggleInterest(tag)} className={`rounded-full border px-3 py-1.5 text-xs transition ${interests.includes(tag) ? "border-primary bg-primary text-primary-foreground" : "border-border bg-card text-muted-foreground hover:bg-secondary"}`}>
                {tag}
              </button>
            ))}
          </div>
        </Card>

        <Card className="flex min-h-[720px] flex-col overflow-hidden shadow-lg">
          <header className="flex items-center justify-between border-b border-border px-5 py-4">
            <div>
              <h2 className="text-xl font-semibold">AI 对话</h2>
              <p className="text-xs text-muted-foreground">{conversationId ? `会话 ${conversationId}` : "输入问题会自动创建导览会话"}</p>
            </div>
            {loading ? <Button variant="outline" size="sm" onClick={() => abortRef.current?.abort()}>停止回复</Button> : null}
          </header>
          <div className="flex-1 space-y-4 overflow-auto bg-white/55 p-5">
            {messages.map((message, index) => (
              <div key={index} className={`flex ${message.role === "user" ? "justify-end" : "justify-start"}`}>
                <div className={`max-w-[78%] rounded-2xl px-4 py-3 text-sm leading-7 shadow-sm ${message.role === "user" ? "bg-primary text-primary-foreground" : "border border-border bg-card text-foreground"}`}>
                  {message.content || <span className="text-muted-foreground">正在组织回答...</span>}
                </div>
              </div>
            ))}
          </div>
          {error ? <p className="mx-5 mt-3 rounded-lg bg-destructive/10 px-3 py-2 text-sm text-destructive">{error}</p> : null}
          <div className="border-t border-border p-4">
            <div className="mb-3 flex flex-wrap gap-2">
              {quickQuestions.map((item) => <Button key={item} variant="outline" size="sm" onClick={() => sendMessage(item)}>{item}</Button>)}
            </div>
            <div className="grid grid-cols-[auto_1fr_auto_auto] items-end gap-2">
              <Button variant={recording ? "default" : "outline"} size="icon" title="语音输入" onClick={toggleRecording}><Mic className="h-4 w-4" /></Button>
              <Textarea
                className="min-h-11 resize-none"
                value={input}
                onChange={(event) => setInput(event.target.value)}
                placeholder="有问题，尽管问"
                onKeyDown={(event) => {
                  if (event.key === "Enter" && !event.shiftKey) {
                    event.preventDefault()
                    sendMessage()
                  }
                }}
              />
              <Button variant="outline" size="icon" title="朗读上一条回复" onClick={speakLastReply}><Volume2 className="h-4 w-4" /></Button>
              <Button size="icon" onClick={() => sendMessage()} disabled={!input.trim() || loading}><Send className="h-4 w-4" /></Button>
            </div>
          </div>
        </Card>

        <div className="space-y-5">
          <Card className="p-5 shadow-lg">
            <h2 className="mb-3 flex items-center gap-2 text-lg font-semibold"><Sparkles className="h-5 w-5 text-primary" />快捷问题推荐</h2>
            <div className="space-y-2">
              {quickQuestions.map((item) => (
                <button key={item} type="button" onClick={() => sendMessage(item)} className="w-full rounded-[8px] border border-border bg-card px-3 py-3 text-left text-sm transition hover:border-primary/40 hover:bg-primary/5">
                  {item}
                </button>
              ))}
            </div>
          </Card>
          <Card className="p-5 shadow-lg">
            <h2 className="mb-3 flex items-center gap-2 text-lg font-semibold"><History className="h-5 w-5 text-primary" />历史会话</h2>
            <div className="max-h-72 space-y-2 overflow-auto">
              {history.length ? history.map((item) => (
                <div key={item.id} className="rounded-[8px] border border-border px-3 py-3">
                  <p className="truncate text-sm font-medium">{item.title}</p>
                  <p className="mt-1 truncate text-xs text-muted-foreground">{item.updatedAt}</p>
                </div>
              )) : <div className="grid min-h-28 place-items-center rounded-[8px] border border-dashed border-border text-sm text-muted-foreground">暂无历史会话</div>}
            </div>
          </Card>
        </div>
      </section>

      <section id="map" className="mx-auto max-w-7xl px-4 py-10 md:px-6">
        <div className="grid gap-5 lg:grid-cols-[1.15fr_.85fr]">
          <Card className="relative min-h-[460px] overflow-hidden p-6 shadow-lg">
            <div className="absolute inset-0 bg-[radial-gradient(circle_at_20%_20%,rgba(16,185,129,.22),transparent_28%),radial-gradient(circle_at_70%_60%,rgba(0,122,47,.18),transparent_30%)]" />
            <div className="relative h-full rounded-[8px] border border-emerald-900/10 bg-white/70 p-5">
              <div className="grid h-full place-items-center">
                <div className="relative h-72 w-full max-w-xl">
                  {recommendedSpots.map((spot, index) => (
                    <div key={spot.name} className="absolute" style={{ left: `${18 + index * 27}%`, top: `${24 + (index % 2) * 28}%` }}>
                      <div className="grid h-14 w-14 place-items-center rounded-full bg-primary text-white shadow-lg">
                        <Navigation className="h-5 w-5" />
                      </div>
                      <p className="mt-2 whitespace-nowrap rounded-full bg-white px-3 py-1 text-xs font-semibold shadow">{spot.name}</p>
                    </div>
                  ))}
                  <div className="absolute left-[23%] top-[35%] h-1 w-[58%] rotate-6 rounded-full bg-primary/35" />
                  <div className="absolute left-[49%] top-[49%] h-1 w-[30%] -rotate-12 rounded-full bg-primary/35" />
                </div>
              </div>
            </div>
          </Card>
          <Card className="p-6 shadow-lg">
            <h2 className="text-2xl font-semibold">地图导览</h2>
            <p className="mt-3 text-sm leading-7 text-muted-foreground">
              地图区域突出数字人陪同路线。选择兴趣后，可以让数字人即时生成路线，并在对话里继续追问每个景点的讲解、停留时间和服务设施。
            </p>
            <div className="mt-5 flex flex-wrap gap-2">
              {interests.map((item) => <span key={item} className="rounded-full bg-primary/10 px-3 py-1 text-xs font-medium text-primary">{item}</span>)}
              {!interests.length && <span className="text-sm text-muted-foreground">尚未选择兴趣偏好</span>}
            </div>
            <Button className="mt-6 w-full" onClick={recommendRoute}><Compass className="h-4 w-4" />生成我的路线</Button>
          </Card>
        </div>
      </section>

      <section id="spots" className="mx-auto max-w-7xl px-4 pb-14 pt-10 md:px-6">
        <div className="mb-6 flex items-end justify-between gap-4">
          <div>
            <h2 className="text-3xl font-semibold">景点推荐</h2>
            <p className="mt-2 text-sm text-muted-foreground">每个推荐都可以继续交给数字人讲解。</p>
          </div>
        </div>
        <div className="grid gap-4 md:grid-cols-3">
          {recommendedSpots.map((spot) => (
            <Card key={spot.name} className="overflow-hidden shadow-lg">
              <div className="h-40 bg-cover bg-center" style={{ backgroundImage: `url(${scenicImages[0]})` }} />
              <div className="p-5">
                <h3 className="text-xl font-semibold">{spot.name}</h3>
                <p className="mt-2 min-h-12 text-sm leading-6 text-muted-foreground">{spot.note}</p>
                <Button className="mt-4 w-full" variant="outline" onClick={() => sendMessage(`请介绍${spot.name}，并告诉我适合怎么游览。`)}>
                  <Star className="h-4 w-4" />
                  让数字人讲解
                </Button>
              </div>
            </Card>
          ))}
        </div>
      </section>

      <FrostedAdminLogin open={loginOpen} onClose={() => setLoginOpen(false)} />

      <style>{`
        html { scroll-behavior: smooth; }
        @keyframes scenicFade {
          0% { opacity: 0; transform: scale(1.02); }
          6% { opacity: 1; }
          26% { opacity: 1; }
          34% { opacity: 0; transform: scale(1.08); }
          100% { opacity: 0; transform: scale(1.08); }
        }
      `}</style>
    </main>
  )
}
